const d = items[0].json;

function score(val){ if(!val) return 2; val = val.toString().toLowerCase(); if(val.includes('low')||val.includes('short')||val.includes('beginner')||val.includes('exit')) return 1; if(val.includes('medium')||val.includes('moderate')||val.includes('balanced')) return 2; return 3; }

const total = score(d.investmentHorizon) + score(d.incomeStability) + score(d.wealthPortion) + score(d.riskReaction) + score(d.experience) + score(d.goal) + score(d.returnExpectation);

let profile = 'Moderate';
if(total <= 11) profile = 'Conservative';
else if(total >= 17) profile = 'Aggressive';

return [{ json: { ...d, riskScore: total, riskProfile: profile } }];

const d = items[0].json;

let allocation;
let riskNumeric;

switch(d.riskProfile) {
  case 'Conservative':
    allocation = { equity: 30, debt: 60, gold: 10 };
    riskNumeric = 1;
    break;
  case 'Moderate':
    allocation = { equity: 50, debt: 40, gold: 10 };
    riskNumeric = 2;
    break;
  case 'Aggressive':
    allocation = { equity: 70, debt: 20, gold: 10 };
    riskNumeric = 3;
    break;
}

const expectedReturn = allocation.equity*0.14/100 + allocation.debt*0.07/100 + allocation.gold*0.10/100;
const years = d.targetYears || 10;
const multiplier = Math.pow(1 + expectedReturn, years);

return [{
  json: {
    clientName: d.clientName,
    clientEmail: d.clientEmail,
    riskScore: d.riskScore,
    riskProfile: d.riskProfile,
    riskNumeric,
    equity: allocation.equity,
    debt: allocation.debt,
    gold: allocation.gold,
    expectedReturn,
    projectionMultiplier: multiplier,
    submissionMonth: new Date().toISOString().slice(0,7)
  }
}];

